  ('judicial-388a63c0-moex-00150', 'judicial-388a63c0', 'judicial-388a63c0-moex-110-916530c6', 'sub-judicial-388a63c0-02', NULL, 'essay', '甲、乙為男女朋友，因分手爭吵。甲打電話到乙家告訴乙之母親，限當
天乙出面解決，否則放火燒乙家。乙置之不理，甲遂將自家瓦斯桶拉到
乙家公寓樓梯間，大喊要乙一起玉石俱焚，以瓦斯管將液化石油氣從前
陽臺導入乙房子內，待液化石油氣蓄積瀰漫房間達爆炸界限，即於房門
附近，以打火機點火引爆液化石油氣，瞬間產生氣爆並引發火勢，窗戶
玻璃受氣爆產生之壓力波及而破碎損壞，家具燒燬，並波及樓上鄰居房
屋，幸因民眾發現瓦斯氣爆旋即報案，經消防隊趕赴現場及時撲滅火勢，
人員無傷。請問甲之行為如何論斷？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:26+00:00", "source_pdf_sha1": "bd41812f659a", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "105", "s": "0503", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "司法事務官法律事務組"}'::jsonb, NULL)
